#include "benchmark/unitBench/scenarios/codecs/sddl2.h"

#include <stdlib.h> // abort

#include "openzl/codecs/zl_sddl2.h"    // ZL_Compressor_registerSDDL2Graph, SDDL2_BYTECODE_PARAM
#include "openzl/zl_compressor.h"               // ZL_Compressor_setParameter
#include "openzl/zl_localParams.h"              // ZL_LocalParams

/* ==================================================
 * SDDL2 Bytecode for SAO
 * ==================================================
 * Copied from: examples/sddl2_asm/sao_silesia.asm
 * which was generated by: tools/sddl/assembler/sddl2_assembler.py
 *
 * This bytecode implements the SAO parser using push.remaining
 * to dynamically calculate the number of star records:
 *   1. Create 28-byte header segment (unspecified)
 *   2. Build StarEntry structure type (6 fields)
 *   3. Use push.remaining to calculate star count
 *   4. Create tagged segment with StarEntry[] type
 */

static const unsigned char sao_sddl2_bytecode[] = {
    0x03, 0x00, 0x01, 0x00, 0x1c, 0x00, 0x00, 0x00, 0x01, 0x00, 0x0c, 0x00,
    0x35, 0x01, 0x01, 0x00, 0x35, 0x01, 0x01, 0x00, 0x14, 0x01, 0x01, 0x00,
    0x00, 0x01, 0x01, 0x00, 0x03, 0x00, 0x01, 0x00, 0x02, 0x00, 0x00, 0x00,
    0x01, 0x00, 0x08, 0x00, 0x37, 0x01, 0x01, 0x00, 0x37, 0x01, 0x01, 0x00,
    0x03, 0x00, 0x01, 0x00, 0x06, 0x00, 0x00, 0x00, 0x02, 0x00, 0x08, 0x00,
    0x05, 0x00, 0x01, 0x00, 0x02, 0x00, 0x00, 0x00, 0x04, 0x00, 0x07, 0x00,
    0x81, 0x00, 0x01, 0x00, 0x02, 0x00, 0x01, 0x00, 0x1c, 0x00, 0x00, 0x00,
    0x04, 0x00, 0x02, 0x00, 0x02, 0x00, 0x0c, 0x00, 0x01, 0x00, 0x05, 0x00
};

static const size_t sao_sddl2_bytecode_size = sizeof(sao_sddl2_bytecode);

/* ==================================================
 * Graph for SAO using SDDL2 interpreter
 * ==================================================
 */

ZL_GraphID sao_graph_sddl2(ZL_Compressor* cgraph)
{
    // Set format version and compression level
    if (ZL_isError(ZL_Compressor_setParameter(
                cgraph, ZL_CParam_formatVersion, ZL_MAX_FORMAT_VERSION))) {
        abort();
    }
    if (ZL_isError(ZL_Compressor_setParameter(
                cgraph, ZL_CParam_compressionLevel, 1))) {
        abort();
    }

    // Register SDDL2_parse with STORE destination for benchmarking
    ZL_GraphID sddl2_graph = ZL_Compressor_registerSDDL2Graph(
            cgraph,
            sao_sddl2_bytecode,
            sao_sddl2_bytecode_size,
            ZL_GRAPH_STORE);

    if (!ZL_GraphID_isValid(sddl2_graph)) {
        abort();
    }

    return sddl2_graph;
}
